  private OpGets() { super("<-"); }
  public <ResType> ResType accept(BinOpVisitor<ResType> v) {
    return v.forOpGets();
  }
}

/* UnOpApp is a Term because it does not need enclosing parentheses when appearing in a binary expression */
class UnOpApp implements Term {
  private UnOp rator;
  private AST arg;

  UnOpApp(UnOp r, AST a) { rator = r; arg = a; }

  public UnOp rator() { return rator; }
  public AST arg() { return arg; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forUnOpApp(this); }
  public String toString() { return rator + " " + arg; }
}

class BinOpApp implements Term {
  private BinOp rator;
  private AST arg1, arg2;

  BinOpApp(BinOp r, AST a1, AST a2) { rator = r; arg1 = a1; arg2 = a2; }

  public BinOp rator() { return rator; }
  public AST arg1() { return arg1; }
  public AST arg2() { return arg2; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBinOpApp(this); }
  public String toString() {
    return "(" + toString(arg1) + " " + rator + " " + toString(arg2) + ")"; 
  }
  private String toString(AST arg) {
    String argString = arg.toString();
    if (! (arg instanceof Term)) return "(" + argString + ")";
    else return argString;
  }
}

class Map implements AST {
  private TypedId[] vars;
  private AST body;

  Map(TypedId[] v, AST b) { vars = v; body = b; }
  public TypedId[] vars() { return vars; }
  public AST body() { return body; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forMap(this); }
  public String toString() { 
    return "map " + ToString.toString(vars,",") + " to " + body;
  }
}  

class App implements Term {
  private AST rator;
  private AST[] args;

  App(AST r, AST[] a) { rator = r; args = a; }

  public AST rator() { return rator; }
  public AST[] args() { return args; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forApp(this); }
  public String toString() { 
    if ((rator instanceof PrimFun) || (rator instanceof Variable))
      return rator + "(" + ToString.toString(args,", ") + ")"; 
    else
      return "(" +  rator + ")(" + ToString.toString(args,", ") + ")"; 
  }
}  

class If implements AST {
  private AST test, conseq, alt;
  If(AST t, AST c, AST a) { test = t; conseq = c; alt = a; }

  public AST test() { return test; }
  public AST conseq() { return conseq; }
  public AST alt() { return alt; }
  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forIf(this); }
  public String toString() { 
    return "if " + test + " then " + conseq + " else " + alt ; 
  }
}  

class Let implements AST {
  private Def[] defs;
  private AST body;
  Let(Def[] d, AST b) { defs = d; body = b; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forLet(this); }
  public Def[] defs() { return defs; }
  public AST body() { return body; }
  public String toString() { 
    return "let " + ToString.toString(defs," ") + " in " + body; 
  }

  /* Commonly used non-essential methods */
  /** Returns the vars that are locally defined in this Let. */
  public TypedId[] vars() {
    int n = defs.length;
    TypedId[] vars = new TypedId[n];
    for(int i = 0; i < n; i++) { vars[i] = defs[i].lhs(); }
    return vars;
  }
  /** Returns the exps that appear on the rhs of defs in this Let. */
  public AST[] exps() {
    int n = defs.length;
    AST[] exps = new AST[n];
    for(int i = 0; i < n; i++) { exps[i] = defs[i].rhs(); }
    return exps;
  }
}

/** A Block is a non-empty sequence of statements (expressions) that returns the value of the last
  * statement (expression).  The preceding statements are included solely for their side-effect
  * (changes to the values stored in boxes)
  * Hence, a block cannot appear as the first argument in a binary operation unless it is
  * enclosed in parentheses. The empty block is a parser error (ParseException).
  */
class Block implements AST {
  private AST[] exps;
  public Block(AST[] es) {
    exps = es;
  }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBlock(this); }

  public AST[] exps() { return exps; }

  public String toString() {
    return "{" + ToString.toString(exps, "; ") + "}";
  }
}

class TypedId {
  private Variable id;
  private Type type;
  TypedId(Variable v, Type t) { id = v; type = t; }
  public Variable id() { return id; }
  public Type type() { return type; }
  public String toString() { return id + " : " + type; }
}

/** Def class representing a definition embedded inside a Let. */
class Def {
  private TypedId lhs;
  private AST rhs;  

  Def(TypedId l, AST r) { lhs = l; rhs = r; }
  public TypedId lhs() { return lhs; }
  public AST rhs() { return rhs; }

  public String toString() { return lhs + " := " + rhs + ";"; }
}

/** Dummy class containing an improved toString method for arrays. */
class ToString {

  public static String toString(Object[] a, String s) {
    StringBuffer result = new StringBuffer();
    for (int i = 0; i < a.length; i++) {
      if (i > 0) result.append(s);
      Object elt = a[i];
      String eltString = (elt instanceof Object[]) ?
        toString((Object[]) elt, s) : elt.toString();
      result.append(eltString);
    }
    return result.toString();
  }
}

/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error, 
  * throws a SyntaxException.
  */
class CheckVisitor implements ASTVisitor<Void> {
  /** Empty symbol table. */
  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();
  
  /** Symbol table to detect free variables. */
  PureList<Variable> env;
  
  /** Root form of CheckVisitor. */
  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);

  CheckVisitor(PureList<Variable> e) { env = e; }
  
  /** Helper method that converts an array to a PureList. */
  public static <T> PureList<T> arrayToList(T[] array) {
    int n = array.length;
    PureList<T> list = new Empty<T>();
    for(int i = n-1; i >= 0; i--) { list = list.cons(array[i]); }
    return list;
  }
  
  /*  Visitor methods. */
  public Void forIntConstant(IntConstant i) { return null; }
  public Void forBoolConstant(BoolConstant b) { return null; }
  public Void forEmptyConstant(EmptyConstant n) { return null; }
  
  public Void forVariable(Variable v) {
    Variable match = env.accept(new LookupVisitor<Variable>(v));
    if (match == null) throw new SyntaxException("variable " + v + " is unbound");
    return null;
  }

  public Void forPrimFun(PrimFun f) { return null;  }
  
  public Void forUnOpApp(UnOpApp u) {
    u.arg().accept(this);  // mzy throw a SyntaxException
    return null;
  }
  
  public Void forBinOpApp(BinOpApp b) {
    b.arg1().accept(this); // may throw a SyntaxException
    b.arg2().accept(this); // may throw a SyntaxException
    return null;
  }

  public Void forApp(App a) {
    a.rator().accept(this); // may throw a SyntaxException
    AST[] args = a.args();
    int n = args.length;
    for(int i = 0; i < n; i++) { args[i].accept(this); } // may throw a SyntaxException
    return null;
  }

  public Void forMap(Map m) {
    // Check for duplicates in Map vars & construct newEnv for Map body
    TypedId[] tids = m.vars();
    int n = tids.length;
    Variable[] vars = new Variable[n];
    for (int i = 0; i < n; i++) vars[i] = tids[i].id();
    
    PureList<Variable> varList = arrayToList(vars);
    varList.accept(AnyDuplicatesVisitor.ONLY);  // may throw a SyntaxException
    PureList<Variable> newEnv = env;
    for(int i = n-1; i >= 0; i--) { newEnv = newEnv.cons(vars[i]); }  // vars appear in newEnv in same order as code, but this property is unimportant
    m.body().accept(new CheckVisitor(newEnv));  // may throw a SyntaxException
    return null;
  }

  public Void forIf(If i) {
    i.test().accept(this);
    i.conseq().accept(this);
    i.alt().accept(this);
    return null;
  }

  public Void forLet(Let l) {
    // Check for duplicates in Let vars, check Let rhs's and body using newEnv including let vars
    TypedId[] tids = l.vars();
    int n = tids.length;
    Variable[] vars = new Variable[n];
    for (int i = 0; i < n; i++) vars[i] = tids[i].id();

    PureList<Variable> varList = arrayToList(vars);
    varList.accept(AnyDuplicatesVisitor.ONLY);  // may throw a SyntaxException
    AST[] exps = l.exps();
    PureList<Variable> newEnv = env;
    for(int i = n-1; i >= 0; i--) { newEnv = newEnv.cons(vars[i]); }  // vars appear in newEnv in same order as code
    CheckVisitor newVisitor = new CheckVisitor(newEnv);
    for(int i = 0; i < n; i++) { exps[i].accept(newVisitor); } // may throw a SyntaxException
    l.body().accept(newVisitor); // may throw a SyntaxException
    return null;
  }
  
  public Void forBlock(Block b) {
    AST[] exps = b.exps();
    int n = exps.length;
    for (int i = 0; i < n; i++) exps[i].accept(this);  // may throw a SyntaxException
    return null;
  }
}

/** Singleton visitor that checks for duplicate variables in a symbol table. Returns normally unless an error is found.
  * Throws a SyntaxException on error.
  */
class AnyDuplicatesVisitor implements PureListVisitor<Variable, Void> {
  /** Singleton instance. */
  public static AnyDuplicatesVisitor ONLY = new AnyDuplicatesVisitor();
  private AnyDuplicatesVisitor() { }
  
  /* Visitor methods. */
  public Void forEmpty(Empty<Variable> e) { return null; }

  public Void forCons(Cons<Variable> c) {
    if (c.rest().contains(c.first()))
      throw new SyntaxException(c.first() + " is declared twice in the same scope");
    c.rest().accept(this); // may throw a SyntaxException
    return null;
  }
}

/** Exception type thrown by the context-sensitive checker. */
class SyntaxException extends RuntimeException {
  SyntaxException(String s) { super(s); }
}

/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    } 
    finally {
      try { in.rdr.close(); } 
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);

    /* Invoke the CheckVisitor confirm prog does not contain free variables or parameter lists with duplicate names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
//    if (token == Lexer.LETREC) return parseLetRec();  // supports addition of letrec
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /*  Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      // including closing brace
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begin with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
//      System.err.println("exp updated to: " + exp);
      next = in.peek();
    }
//    System.err.println("parseTerm returning " + exp);
    return exp;
  }

  /** Parses:
    *   <term>     ::= { <unop> } <term> | <constant> | <factor> {( <exp-list> )}
    *   <constant> ::= <null> | <int> | <bool>
    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseTerm(Token token) {

    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op,"unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    if (token instanceof Constant) {
      if (token instanceof EmptyConstant) {
        Token next = in.readToken();
        if (next != Lexer.COLON) error(next, "':' after 'empty'");
        Type t = parseType();
        return new EmptyConstant(t);
      }
      return (Constant) token;
    }

    if (token instanceof PrimFun) {
      Token next = in.readToken();
      if (next != LeftParen.ONLY) error(next, "'(' after primitive");
      AST[] exps = parseArgs();
      return new App((PrimFun)token, exps);
    }

    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();  // remove next from input stream
      AST[] exps = parseArgs();  // including closing paren
      return new App(factor,exps);
    }
    return factor;
  }

  /** Parses:  <factor>   ::= ( <exp> ) | <variable>
    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseFactor(Token token) {

    if (token == LeftParen.ONLY) { 
      /* Parse a parenthesized expression */
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token,"`)'");
      return exp;
    }

    if (! (token instanceof Variable))
      error(token,"constant, primitive, variable, or `('");

    // Term = Variable
    return (Term) token;
  }      

  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
  private AST parseIf() {

    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1,"`then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2,"`else'");
    AST alt = parseExp();
    return new If(test,conseq,alt);
  }


  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */ 
  private AST parseLet() {
    Def[] defs = parseDefs(false); 
    // consumes `in'; false means rhs may be non Map
    AST body = parseExp();
    return new Let(defs,body);
  }

  /* Supports the parsing of separate 'letrec' construct */
//  /** Parses `letrec <prop-def-list> in <exp>' given that `letrec' has already been read. */
//  private AST parseLetRec() {
//    
//    Def[] defs = parseDefs(true);
//    // consumes `in'; true means each rhs must be a Map
//    AST body = parseExp();
//    return new LetRec(defs,body);
//  }

  /* Parses `map <id-list> to <exp>' given that `map' has already been read. */
  private AST parseMap() {

    TypedId[] vars = parseVars(); // consumes the delimiter `to'
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses `<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <empty> ::=
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list> 
    */
  private AST[] parseExps(Token separator, Token delim) {

    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume RightParen
      return new AST[0];
    }

    // next is still at front of input stream

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next,"`,' or `)'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY,RightParen.ONLY); }

  /** Parses <id-list> where
    *   <id-list>       ::= <empty> | <prop-id-list>
    *   <prop-id-list>  ::= <id> | <id> , <id-list> 
    *  NOTE: consumes `to' following <id-list>
    */
  private TypedId[] parseVars() {

    LinkedList<TypedId> vars = new LinkedList<TypedId>();
    Token t = in.peek();
    if (t == Lexer.TO) { in.readToken(); return new TypedId[0]; }

    do {
      vars.addLast(parseTypedId());
      t = in.readToken();
      if (t == Lexer.TO) break; 
      if (t != Comma.ONLY) error(t, "`to' or `, '");
    } while (true);
    return (TypedId[]) vars.toArray(new TypedId[0]);
  }

  private TypedId parseTypedId() {
    Token t = in.readToken();
    if (!(t instanceof Variable)) error(t, "variable");
    Token colon = in.readToken();
    if (colon != Lexer.COLON) error(colon, "':'");
    Type type = parseType();
    return new TypedId((Variable)t, type);
  }

  private Type parseType() {
    Token t = in.readToken();
    if (t == Lexer.UNIT) return UnitType.ONLY;
    if (t == Lexer.INT) return IntType.ONLY;
    if (t == Lexer.BOOL) return BoolType.ONLY;
    if (t == Lexer.LIST) return new ListType(parseType());
    if (t == Lexer.REF) return new RefType(parseType());
    if (t == LeftParen.ONLY) {
      LinkedList<Type> types = new LinkedList<Type>();
      Token next = in.peek();
      if (next != Lexer.ARROW) {
        do {
          types.add(parseType());
          next = in.readToken();
        } while (next == Comma.ONLY);
        if (next != Lexer.ARROW) error(next, "'->'");
      } else {
        in.readToken(); // consume ARROW
      }

      Type result = parseType();
      Token close = in.readToken();
      if (close != RightParen.ONLY) error(close, "')'");
      return new FunType(types.toArray(new Type[0]), result);
    }
    error(t, "type");
    return null; // unreachable
  }

  /** Parses a proper list of definitions, more technically parses
    *   <prop-def-list> ::= <def> | <def> <def-list> 
    *   NOTE: consumes `in' following <prop-def-list> */

  private Def[] parseDefs(boolean forceMap) {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);        
      if (forceMap && (! (d.rhs() instanceof Map)))
        throw new ParseException("right hand side of definition `" + d + "' is not a map expression");
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses 
    *   <id> : <type> := <exp> ;
    * which is <def> given that first token var has been read.
    */
  private Def parseDef(Token var) {
    if (! (var instanceof Variable)) error(var, "variable");
    Token colon = in.readToken();
    if (colon != Lexer.COLON) error(colon, "':'");
    Type type = parseType();
    TypedId tid = new TypedId((Variable)var, type);

    Token key = in.readToken();
    if (key != Lexer.BIND) error (key,"`:='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi,"`;'");
    return new Def(tid, exp);
  }

  private AST error(Token found, String expected) {
//    for (int i = 0; i < 10; i++) {
//      System.out.println(in.readToken());
//    }   
    throw new ParseException("Token `" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy "main" method that perhaps should be deleted. */
  public static void main(String[] args) throws IOException {
    // check for legal argument list 
    if (args.length == 0) {
//      System.out.println("Usage: java Parser <filename>");
      return;
    }
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
//    System.out.println("Parse tree is: " + prog);
  }
}

/** Jam lexer class for all assignments.              
  * Given a Lexer object, the next token in that input stream being processed by the Lexer is returned by the
  * readToken() method; it throws a ParseException (a form of RuntimeException) if it encounters a syntax error.  
  * Calling readToken() advances the cursor in the input stream to the next token.
  * 
  * The method peek() in the Lexer class has the same behavior as readToken() except for the fact that it does not
  * advance the cursor.
  */

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.IOException;
import java.io.Reader;
import java.io.StreamTokenizer;
import java.util.HashMap;

class Lexer extends StreamTokenizer {

  /* short names for StreamTokenizer codes */

  public static final int WORD = StreamTokenizer.TT_WORD; 
  public static final int NUMBER = StreamTokenizer.TT_NUMBER; 
  public static final int EOF = StreamTokenizer.TT_EOF; 
  public static final int EOL = StreamTokenizer.TT_EOL; 

  /* operator Tokens */

  // <unop>  ::= <sign> | ~   | ! 
  // <binop> ::= <sign> | "*" | / | = | != | < | > | <= | >= | & | "|" | <- 
  // <sign>  ::= "+" | -

  //  Note: there is no class distinction between <unop> and <binop> at 
  //  lexical level because of ambiguity; <sign> belongs to both

  public static final OpToken PLUS = OpToken.newBothOpToken(UnOpPlus.ONLY, BinOpPlus.ONLY); 
  public static final OpToken MINUS = OpToken.newBothOpToken(UnOpMinus.ONLY, BinOpMinus.ONLY);
  public static final OpToken TIMES = OpToken.newBinOpToken(OpTimes.ONLY);
  public static final OpToken DIVIDE = OpToken.newBinOpToken(OpDivide.ONLY);
  public static final OpToken EQUALS = OpToken.newBinOpToken(OpEquals.ONLY);
  public static final OpToken NOT_EQUALS = OpToken.newBinOpToken(OpNotEquals.ONLY);
  public static final OpToken LESS_THAN = OpToken.newBinOpToken(OpLessThan.ONLY);
  public static final OpToken GREATER_THAN = OpToken.newBinOpToken(OpGreaterThan.ONLY);
  public static final OpToken LESS_THAN_EQUALS = OpToken.newBinOpToken(OpLessThanEquals.ONLY);
  public static final OpToken GREATER_THAN_EQUALS = OpToken.newBinOpToken(OpGreaterThanEquals.ONLY);
  public static final OpToken NOT = OpToken.newUnOpToken(OpTilde.ONLY);
  public static final OpToken AND = OpToken.newBinOpToken(OpAnd.ONLY);
  public static final OpToken OR = OpToken.newBinOpToken(OpOr.ONLY);

  /* Used to support reference cells. */
  public static final OpToken BANG = OpToken.newUnOpToken(OpBang.ONLY);
  public static final OpToken GETS = OpToken.newBinOpToken(OpGets.ONLY);
  public static final OpToken REF = OpToken.newUnOpToken(OpRef.ONLY);

  /* Keywords */

  public static final KeyWord IF     = new KeyWord("if");
  public static final KeyWord THEN   = new KeyWord("then");
  public static final KeyWord ELSE   = new KeyWord("else");
  public static final KeyWord LET    = new KeyWord("let");
//  public static final KeyWord LETREC = new KeyWord("letrec");   // Used to support separate letrec construction
  public static final KeyWord IN     = new KeyWord("in");
  public static final KeyWord MAP    = new KeyWord("map");
  public static final KeyWord TO     = new KeyWord("to");
  public static final KeyWord BIND   = new KeyWord(":=");
  public static final KeyWord COLON  = new KeyWord(":");
  public static final KeyWord ARROW  = new KeyWord("->");

  /* Type Keywords */
  public static final KeyWord UNIT = new KeyWord("unit");
  public static final KeyWord INT  = new KeyWord("int");
  public static final KeyWord BOOL = new KeyWord("bool");
  public static final KeyWord LIST = new KeyWord("list");
  // REF is already defined as an OpToken, but used in types too

  /* fields */

  /** The Reader from which this lexer reads. */
  public final Reader rdr;

  /* The wordtable for classifying words in token stream */
  public HashMap<String,Token>  wordTable = new HashMap<String,Token>();

  /** The buffer holding the next token in the intput stream; it is used to support the peek() operation, which cannot
    * be implemented using StreamTokenizer pushBack because some Tokens are composed of two StreamTokenizer tokens. */
  Token buffer;

  /* constructors */

  /** Constructs a Lexer for the specified inputStream */
  Lexer(Reader inputStream) {
    super(new BufferedReader(inputStream));
    rdr = inputStream;
    initLexer();
  }

  /** Constructor that uses a File as the input stream. */
  Lexer(String fileName) throws IOException {
    this(new FileReader(fileName));
  }

  /* Initializes lexer tables and the StreamTokenizer that the lexer extends */
  private void initLexer() {

    // configure StreamTokenizer portion of this
    resetSyntax();
    parseNumbers();
    ordinaryChar('-');
    slashSlashComments(true);
    wordChars('0', '9');
    wordChars('a', 'z');
    wordChars('A', 'Z');
    wordChars('_', '_');
    wordChars('?', '?');
    whitespaceChars(0, ' '); 

    // `+' `-' `*' `/' `~' `=' `<' `>' `&' `|' `:' `;' `,' '!'
    // `(' `)' `[' `]' are ordinary characters (self-delimiting)

    initWordTable();
    buffer = null;  // buffer initially empty
  }

  /** Resets the reader embedded in this lexer.  The same file may be scanned multiple times in tests. */
  public void reset() throws ParseException { 
    try { rdr.reset(); }
    catch(IOException e) { throw new ParseException(e); }
  }

  /** Reads tokens until next end-of-line */
  public void flush() throws IOException {
    eolIsSignificant(true);
    while (nextToken() != EOL) ; // eat tokens until EOL
    eolIsSignificant(false);
  }

  /** Returns the next token in the input stream without consuming it */
  public Token peek() { 
    if (buffer == null) buffer = readToken();
    return buffer;
  }

  /** Reads the next token as defined by StreamTokenizer in the input stream (consuming it). */
  private int getToken() {
    // synonymous with nextToken() except for throwing an unchecked 
    // ParseException instead of a checked IOException
    try {
      int tokenType = nextToken();
      return tokenType;
    } catch(IOException e) {
      throw new ParseException("IOException " + e + "thrown by nextToken()");
    }
  }

  /** Reads the next Token in the input stream (consuming it) */
  public Token readToken() {

    /* Uses getToken() to read next token and constructs the Token object representing that token.
     * NOTE: token representations for all Token classes except IntConstant are unique; a HashMap 
     * is used to avoid duplication.  Hence, == can safely be used to compare all Tokens except 
     * IntConstants for equality (assuming that code does not gratuitously create Tokens).  When the
     * stream is reduced to EOT, returns null instead of a Token.
     */

    if (buffer != null) {
      Token token = buffer;
      buffer = null;          // clear buffer
      return token;
    }

    int tokenType = getToken();

    switch (tokenType) {

      case NUMBER:
        int value = (int) nval;
        if (nval == (double) value) return new IntConstant(value);
        throw new ParseException("The number " + nval + " is not a 32 bit integer");
      case WORD:
        Token regToken = wordTable.get(sval);
        if (regToken == null) {
          // must be new variable name
          Variable newVar = new Variable(sval);
          wordTable.put(sval, newVar);
          return newVar;
        }
        return regToken;

      case EOF: return EndOfFile.ONLY;
      case '(': return LeftParen.ONLY;
      case ')': return RightParen.ONLY;
      case '[': return LeftBrack.ONLY;
      case ']': return RightBrack.ONLY;
      case '{': return LeftBrace.ONLY;
      case '}': return RightBrace.ONLY;
      case ',': return Comma.ONLY;
      case ';': return SemiColon.ONLY;

      case '+': return PLUS;  
      case '-':
        tokenType = getToken();
        if (tokenType == '>') return ARROW;
        pushBack();
        return MINUS;
      case '*': return TIMES;  
      case '/': return DIVIDE;  
      case '~': return NOT;  
      case '=': return EQUALS;

      case '<':
        tokenType = getToken();
        if (tokenType == '=') return LESS_THAN_EQUALS;
        if (tokenType == '-') return GETS;    // Used to support reference cells
        pushBack();
        return LESS_THAN; 

      case '>': 
        tokenType = getToken();
        if (tokenType == '=') return GREATER_THAN_EQUALS;  
        pushBack();
        return GREATER_THAN;

      case '!':
        tokenType = getToken();
        if (tokenType == '=') return NOT_EQUALS;
        pushBack();
        return BANG;  // Used to support reference cells 

      case '&': return AND;  
      case '|': return OR;  
      case ':': {
        tokenType = getToken();
        if (tokenType == '=') return BIND;   // ":=" is a keyword
        pushBack();
        return COLON;
      }
      default:  
        throw new 
        ParseException("'" + ((char) tokenType) + "' is not a legal token");
    }
  }

  /** Initializes the table of Strings used to recognize Tokens */
  private void initWordTable() {
    // initialize wordTable

    // constants
    // <empty>  ::= empty
    // <bool>  ::= true | false

    wordTable.put("empty", EmptyConstant.DUMMY);
    wordTable.put("true",  BoolConstant.TRUE);
    wordTable.put("false", BoolConstant.FALSE); 

    // Install primitive functions // (and unary operator named "ref" which is added in Assignment 4)
    // <prim>  ::= empty? | cons? | cons | first | rest 

    wordTable.put("empty?",    EmptyPPrim.ONLY);
    wordTable.put("cons?",     ConsPPrim.ONLY);
    wordTable.put("ref",       REF);            // Supports the addition of reference cells
    wordTable.put("cons",      ConsPrim.ONLY);
    wordTable.put("first",     FirstPrim.ONLY);
    wordTable.put("rest",      RestPrim.ONLY);


    // keywords: if then else let in map to := 
    wordTable.put("if",    Lexer.IF);
    wordTable.put("then",  Lexer.THEN);
    wordTable.put("else",  Lexer.ELSE);
    wordTable.put("let",   Lexer.LET);
    wordTable.put("in",    Lexer.IN);
    wordTable.put("map",   Lexer.MAP);
    wordTable.put("to",    Lexer.TO);    

    // types
    wordTable.put("unit",  Lexer.UNIT);
    wordTable.put("int",   Lexer.INT);
    wordTable.put("bool",  Lexer.BOOL);
    wordTable.put("list",  Lexer.LIST);
  }
}

import junit.framework.TestCase;
import java.io.*;

public class MyAssign5Test extends TestCase {
  public MyAssign5Test(String name) { super(name); }

  private void typeErrorCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.eagerEval();
      fail(name + " should have thrown TypeException");
    } catch (TypeException e) {
      // success
    }
  }

  private void evalCheck(String program, String expected) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals(expected, interp.eagerEval().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals(expected, interp.lazyEval().toString());
  }

  public void testTypeErrors() {
    typeErrorCheck("plus-bool", "1 + true");
    typeErrorCheck("if-int", "if 1 then 2 else 3");
    typeErrorCheck("if-mismatch", "if true then 1 else false");
    typeErrorCheck("app-non-fun", "let x:int := 1; in x(2)");
    typeErrorCheck("arity-mismatch", "(map x:int to x)(1, 2)");
    typeErrorCheck("arg-type-mismatch", "(map x:int to x)(true)");
    typeErrorCheck("let-rhs-mismatch", "let x:int := true; in x");
    typeErrorCheck("cons-mismatch", "cons(1, empty:bool)");
    typeErrorCheck("first-non-list", "first(1)");
    typeErrorCheck("rest-non-list", "rest(1)");
    typeErrorCheck("emptyP-non-list", "empty?(1)");
    typeErrorCheck("bang-non-ref", "!(1)");
    typeErrorCheck("gets-non-ref", "1 <- 2");
    typeErrorCheck("gets-mismatch", "let x:ref int := ref 1; in x <- true");
  }

  public void testPolymorphic() {
    evalCheck("cons(1, empty:int)", "(1)");
    evalCheck("first(cons(true, empty:bool))", "true");
    evalCheck("rest(cons(1, empty:int))", "()");
    evalCheck("empty?(empty:unit)", "true");
    evalCheck("cons?(cons(1, empty:int))", "true");
    evalCheck("let x:ref int := ref 1; in !x", "1");
    evalCheck("let x:ref int := ref 1; in {x <- 2; !x}", "2");
    evalCheck("1 = 1", "true");
    evalCheck("1 = 2", "false");
    evalCheck("true = true", "true");
    evalCheck("empty:int = empty:int", "true");
  }

  public void testComplexTypes() {
    evalCheck("let f: (int -> int) := map x:int to x + 1; in f(5)", "6");
    evalCheck("let f: ((int -> int), int -> int) := map g:(int -> int), x:int to g(x); in f(map y:int to y*y, 3)", "9");
  }
}

